module 1: create a class to store x and y coordinates  
class coordinate {  
  constructor(x, y) {  
    this.x = x;  
    this.y = y;  
  }  
}  

module 2: add a method to calculate the distance from the origin  
distance() {  
  return Math.sqrt(this.x ** 2 + this.y ** 2);  
}  

module 3: add a method to check if the coordinates are palindromic  
isPalindrome() {  
  return this.x.toString() === this.x.toString().split('').reverse().join('');  
}  

module 4: demonstrate the usage of the class  
const point = new coordinate(3, 4);  
console.log(`distance: ${point.distance()}`);  
console.log(`is palindrome: ${point.isPalindrome()}`);  
